    15→pub struct PresenceKeeper {
    16→    config: Config,
    17→    running: Arc<AtomicBool>,
    18→    paused_until: Arc<Mutex<Option<Instant>>>,
    19→}
    20→
    21→impl PresenceKeeper {
    22→    pub fn new(config: Config) -> Self {
    23→        Self {
    24→            config,
    25→            running: Arc::new(AtomicBool::new(false)),
    26→            paused_until: Arc::new(Mutex::new(None)),
    27→        }
    28→    }
    29→
    30→    pub fn update_config(&mut self, config: Config) {
    31→        self.config = config;
    32→    }
    33→
    34→    pub fn is_running(&self) -> bool {
    35→        self.running.load(Ordering::SeqCst)
    36→    }
    37→
    38→    pub fn start(&mut self) {
    39→        if self.running.load(Ordering::SeqCst) {
    40→            return;
    41→        }
    42→
    43→        self.running.store(true, Ordering::SeqCst);
    44→        let running = self.running.clone();
    45→        let paused_until = self.paused_until.clone();
    46→        let config = self.config.clone();
    47→
    48→        thread::spawn(move || {
    49→            let mut mouse = match HumanMouse::new() {
    50→                Ok(m) => m,
    51→                Err(e) => {
    52→                    eprintln!("Failed to initialize mouse: {}", e);
    53→                    running.store(false, Ordering::SeqCst);
    54→                    return;
    55→                }
    56→            };
    57→
    58→            let mut enigo = match Enigo::new(&Settings::default()) {
    59→                Ok(e) => e,
    60→                Err(e) => {
    61→                    eprintln!("Failed to initialize keyboard: {}", e);
    62→                    running.store(false, Ordering::SeqCst);
    63→                    return;
    64→                }
    65→            };
    66→
    67→            while running.load(Ordering::SeqCst) {
    68→                if !config.enabled {
    69→                    thread::sleep(Duration::from_secs(1));
    70→                    continue;
    71→                }
    72→
    73→                // Check if paused
    74→                {
    75→                    let pause = paused_until.lock().unwrap();
    76→                    if let Some(until) = *pause {
    77→                        if Instant::now() < until {
    78→                            drop(pause);
    79→                            thread::sleep(Duration::from_secs(1));
    80→                            continue;
    81→                        }
    82→                    }
    83→                }
    84→
    85→                // Check work hours
    86→                if config.work_hours.enabled && !is_within_work_hours(&config) {
    87→                    thread::sleep(Duration::from_secs(60));
    88→                    continue;
    89→                }
    90→
    91→                // Calculate next interval with variance
    92→                let interval = calculate_interval(&config);
    93→
    94→                // Check for natural break
    95→                let mut rng = rng();
    96→                if config.natural_breaks.enabled && rng.gen_bool(config.natural_breaks.chance) {
    97→                    let break_mins = rng.gen_range(
    98→                        config.natural_breaks.duration_min..=config.natural_breaks.duration_max,
    99→                    );
   100→                    println!("Taking a natural break for {} minutes", break_mins);
   101→                    thread::sleep(Duration::from_secs(break_mins as u64 * 60));
   102→                    continue;
   103→                }
   104→
   105→                // Wait for user to be idle before performing activity
   106→                if !input_monitor::is_user_idle(config.idle_threshold_sec) {
   107→                    let idle_for = input_monitor::seconds_since_last_input();
   108→                    println!(
   109→                        "[Presence] User active (idle {}s, threshold {}s), skipping activity",
   110→                        idle_for, config.idle_threshold_sec
   111→                    );
   112→                    thread::sleep(Duration::from_secs(1));
   113→                    continue;
   114→                }
   115→
   116→                // Perform activity
   117→                let result = match config.mode.as_str() {
   118→                    "mouse" => mouse.human_move(config.human_like),
   119→                    "keyboard" => jiggle_keyboard(&mut enigo),
   120→                    "both" => {
   121→                        if rng.gen_bool(0.5) {
   122→                            mouse.human_move(config.human_like)
   123→                        } else {
   124→                            jiggle_keyboard(&mut enigo)
   125→                        }
   126→                    }
   127→                    _ => mouse.human_move(config.human_like),
   128→                };
   129→
   130→                if let Err(e) = result {
   131→                    eprintln!("Activity failed: {}", e);
   132→                }
   133→
   134→                // Sleep until next activity
   135→                thread::sleep(Duration::from_millis(interval));
   136→            }
   137→        });
   138→    }
   139→
   140→    pub fn stop(&mut self) {
   141→        self.running.store(false, Ordering::SeqCst);
   142→    }
   143→
   144→    pub fn pause(&mut self, minutes: u32) {
   145→        let mut pause = self.paused_until.lock().unwrap();
   146→        *pause = Some(Instant::now() + Duration::from_secs(minutes as u64 * 60));
   147→    }
   148→
   149→    pub fn resume(&mut self) {
   150→        let mut pause = self.paused_until.lock().unwrap();
   151→        *pause = None;
   152→    }
   153→
   154→    pub fn is_paused(&self) -> bool {
   155→        let pause = self.paused_until.lock().unwrap();
   156→        if let Some(until) = *pause {
   157→            if Instant::now() < until {
   158→                return true;
   159→            }
   160→        }
   161→        false
   162→    }
   163→
   164→    pub fn pause_remaining_minutes(&self) -> Option<u32> {
   165→        let pause = self.paused_until.lock().unwrap();
   166→        if let Some(until) = *pause {
   167→            let now = Instant::now();
   168→            if now < until {
   169→                let remaining = until.duration_since(now);
   170→                return Some((remaining.as_secs() / 60 + 1) as u32);
   171→            }
   172→        }
   173→        None
   174→    }
   175→}
   176→
   177→fn calculate_interval(config: &Config) -> u64 {
   178→    let mut rng = rng();
   179→    let base = config.interval_base_ms as f64;
   180→    let variance = base * config.interval_variance;
   181→    let random_offset = rng.gen_range(-variance..variance);
   182→    (base + random_offset).max(30_000.0) as u64 // Minimum 30 seconds
   183→}
   184→
   185→fn jiggle_keyboard(enigo: &mut Enigo) -> Result<(), String> {
   186→    // Press and release Shift key (produces no visible output)
   187→    enigo.key(Key::Shift, enigo::Direction::Press).map_err(|e| e.to_string())?;
   188→    thread::sleep(Duration::from_millis(50));
   189→    enigo.key(Key::Shift, enigo::Direction::Release).map_err(|e| e.to_string())?;
   190→    Ok(())
   191→}
   192→
   193→fn is_within_work_hours(config: &Config) -> bool {
   194→    use chrono::Local;
   195→
   196→    let now = Local::now();
   197→    let current_time = now.format("%H:%M").to_string();
   198→
   199→    current_time >= config.work_hours.start && current_time <= config.work_hours.end
   200→}
