     8→    CGEventTap, CGEventTapLocation, CGEventTapOptions, CGEventTapPlacement, CGEventType,
     9→};
    10→
    11→static LAST_USER_INPUT: AtomicU64 = AtomicU64::new(0);
    12→
    13→fn current_timestamp_ms() -> u64 {
    14→    SystemTime::now()
    15→        .duration_since(UNIX_EPOCH)
    16→        .map(|d| d.as_millis() as u64)
    17→        .unwrap_or(0)
    18→}
    19→
    20→fn update_last_input() {
    21→    LAST_USER_INPUT.store(current_timestamp_ms(), Ordering::SeqCst);
    22→}
    23→
    24→pub fn get_last_input_timestamp() -> u64 {
    25→    LAST_USER_INPUT.load(Ordering::SeqCst)
    26→}
    27→
    28→pub fn is_user_idle(idle_threshold_sec: u64) -> bool {
    29→    let last_input = get_last_input_timestamp();
    30→    if last_input == 0 {
    31→        return true;
    32→    }
    33→    let now = current_timestamp_ms();
    34→    let elapsed_ms = now.saturating_sub(last_input);
    35→    elapsed_ms >= idle_threshold_sec * 1000
    36→}
    37→
    38→pub fn seconds_since_last_input() -> u64 {
    39→    let last_input = get_last_input_timestamp();
    40→    if last_input == 0 {
    41→        return u64::MAX;
    42→    }
    43→    let now = current_timestamp_ms();
    44→    let elapsed_ms = now.saturating_sub(last_input);
    45→    elapsed_ms / 1000
    46→}
