    49→pub fn start_input_monitor() -> Result<(), String> {
    50→    std::thread::spawn(|| {
    51→        let event_types = vec![
    52→            CGEventType::MouseMoved,
    53→            CGEventType::LeftMouseDown,
    54→            CGEventType::LeftMouseUp,
    55→            CGEventType::RightMouseDown,
    56→            CGEventType::RightMouseUp,
    57→            CGEventType::LeftMouseDragged,
    58→            CGEventType::RightMouseDragged,
    59→            CGEventType::KeyDown,
    60→            CGEventType::KeyUp,
    61→            CGEventType::ScrollWheel,
    62→        ];
    63→
    64→        match CGEventTap::new(
    65→            CGEventTapLocation::HID,
    66→            CGEventTapPlacement::HeadInsertEventTap,
    67→            CGEventTapOptions::ListenOnly,
    68→            event_types,
    69→            |_proxy, _event_type, _event| {
    70→                update_last_input();
    71→                None
    72→            },
    73→        ) {
    74→            Ok(tap) => {
    75→                unsafe {
    76→                    let loop_source = tap.mach_port.create_runloop_source(0).unwrap();
    77→                    CFRunLoop::get_current().add_source(&loop_source, kCFRunLoopCommonModes);
    78→                    tap.enable();
    79→                    CFRunLoop::run_current();
    80→                }
    81→            }
    82→            Err(()) => {
    83→                eprintln!(
    84→                    "[InputMonitor] Failed to create CGEventTap. \
    85→                    Make sure the app has Input Monitoring permission."
    86→                );
    87→            }
    88→        }
    89→    });
    90→
    91→    update_last_input();
    92→    println!("[InputMonitor] Started monitoring user input");
    93→    Ok(())
    94→}
